import json

path_papers = locals()['var_function-call-12211220615769207414']
with open(path_papers, 'r') as f:
    papers = json.load(f)

path_cit = locals()['var_function-call-11859459418229751864']
with open(path_cit, 'r') as f:
    citations = json.load(f)

cit_map = {c['title']: c['citation_count'] for c in citations}

total = 0
chi_papers = []

for p in papers:
    text = p['text'][:3000]
    title = p['filename'].replace('.txt', '')
    lines = text.split('\\n') # Escaped backslash

    is_chi = False
    is_other = False

    relevant_lines = lines[:5]
    for l in lines:
        if 'Copyright' in l or 'Permission' in l or 'ACM 978' in l:
            relevant_lines.append(l)

    for line in relevant_lines:
        line_up = line.upper()

        if 'UBICOMP' in line_up or 'CSCW' in line_up or 'OZCHI' in line_up:
            is_other = True

        if 'CHI' in line_up:
            # Check for CHI 20XX or CHI 'XX
            if 'CHI 20' in line_up or "CHI '1" in line_up or "CHI '0" in line_up or "CHI'1" in line_up:
                if 'OZCHI' not in line_up:
                    is_chi = True

    if is_chi and not is_other:
        chi_papers.append(title)
        total += int(cit_map.get(title, 0))
    elif not is_chi and not is_other:
        if 'Conference on Human Factors' in text[:1000]:
            chi_papers.append(title)
            total += int(cit_map.get(title, 0))

print(f'Identified {len(chi_papers)} CHI papers.')
print(f'Total citations: {total}')
print('__RESULT__:')
print(json.dumps(total))

